template:
:doodle {
  @grid: 1 / 100vw 100vh;
  background: #02040a;
  overflow: hidden;
}
background: 
  radial-gradient(circle at @r(0%, 100%) @r(0%, 100%), @p(#00d2ff, #3a7bd5, #6a11cb, #2575fc, #ff00cc) 0%, transparent @r(40%, 80%)),
  radial-gradient(circle at @r(0%, 100%) @r(0%, 100%), @p(#00f2fe, #4facfe, #43e97b, #fa709a) 0%, transparent @r(30%, 70%));
filter: blur(@r(60px, 100px));
opacity: @r(0.3, 0.6);
animation: aura-move @r(20s, 45s) linear infinite alternate;
@keyframes aura-move {
  0% { transform: translate(-15%, -15%) scale(1.2) rotate(0deg); }
  100% { transform: translate(15%, 15%) scale(1.6) rotate(20deg); }
}

:doodle {
  @grid: 12 / 100vw 100vh;
}
@size: @r(80px, 250px);
background: rgba(255, 255, 255, @r(0.02, 0.08));
backdrop-filter: blur(@r(2px, 12px));
border: 1px solid rgba(255, 255, 255, 0.1);
border-radius: @r(10px, 50px);
position: absolute;
left: @r(-10%, 110%);
top: @r(-10%, 110%);
transform: rotate(@r(360deg)) scale(@r(0.5, 1.2));
animation: drift @r(15s, 40s) linear infinite;
@keyframes drift {
  0% { transform: translate(0, 0) rotate(0deg); opacity: 0; }
  20% { opacity: 0.8; }
  80% { opacity: 0.8; }
  100% { transform: translate(@r(-300px, 300px), @r(-300px, 300px)) rotate(@r(180deg, 360deg)); opacity: 0; }
}

:doodle {
  @grid: 1x25 / 100vw 100vh;
}
@size: @r(2px, 4px) @r(100px, 300px);
background: linear-gradient(180deg, hsla(0, 0%, 100%, @r(0.7, 1)), transparent);
border-radius: 50%;
filter: drop-shadow(0 0 8px #fff);
position: absolute;
left: @r(0%, 100%);
top: -40vh;
transform: rotate(155deg);
animation: fall @r(4s, 12s) linear infinite;
animation-delay: -@r(12s);
@keyframes fall {
  from { transform: translateY(0) rotate(155deg); opacity: 1; }
  to { transform: translateY(140vh) rotate(155deg); opacity: 0; }
}

:doodle {
  @grid: 10 / 100%;
  @shape: circle;
}
background: hsla(calc(240 - 6 * @x * @y), 70%, 68%, @r(0.2, 0.5));
backdrop-filter: blur(@r(2px, 5px));
border: 1px solid rgba(255, 255, 255, 0.1);
transform: scale(@r(0.3, 1));
animation: breathe @r(5s, 10s) ease-in-out infinite alternate;
@keyframes breathe {
  0% { transform: scale(@r(0.3, 0.5)) translate(@r(-20px, 20px), @r(-20px, 20px)); opacity: 0.3; }
  100% { transform: scale(@r(0.8, 1.2)) translate(@r(-10px, 10px), @r(-10px, 10px)); opacity: 0.7; }
}

:doodle {
  @grid: 18 / 100vmax;
}
border-left: 1px solid hsla(@r(200, 260), 70%, 60%, @r(0.1, 0.3));
border-top: 1px solid hsla(@r(200, 260), 70%, 60%, @r(0.1, 0.3));
@random(.15) {
  background: linear-gradient(hsla(@r(360), 80%, 70%, 0.5), transparent);
  box-shadow: 0 0 15px hsla(@lr, 80%, 70%, 0.3);
}
transition: all 0.4s ease;
:hover { background: rgba(255, 255, 255, 0.1); filter: brightness(1.5); }

:doodle {
  @grid: 1 / 100vw 100vh;
  background: #05070a;
}
@content: @svg(
  viewBox: 0 0 100 100;
  stroke: #aeacfb;
  stroke-width: .05;
  line*150 {
    draw: @r(5s, 10s);
    opacity: @r(0.1, 0.4);
    x1: @r(100); y1: @r(100);
    x2: @calc(@x1 + @r(-15, 15));
    y2: @calc(@y1 + @r(-15, 15));
  }
  circle*100 {
    r: @r(0.1, 0.3);
    cx: @r(100); cy: @r(100);
    fill: @p(#fff, #aeacfb);
    animation: twinkle @r(2s, 5s) ease-in-out infinite alternate;
  }
);
@keyframes twinkle { 0% { opacity: 0.2; } 100% { opacity: 1; transform: scale(1.5); } }

:doodle {
  @grid: 1 / 100vw 100vh;
}
@place: center;
@size: 110vmin;
background: radial-gradient(circle, hsla(@r(360), 100%, 70%, 0.6), hsla(@lr, 100%, 50%, 0.4), transparent 70%);
mask: @svg-polygon(split: 500; r: cos(6t)^3 + sin(6t) + 0.5;);
animation: rotate-pulse 30s linear infinite;
@keyframes rotate-pulse {
  0% { transform: rotate(0) scale(0.9); opacity: 0.5; }
  50% { transform: rotate(180deg) scale(1.1); opacity: 0.8; }
  100% { transform: rotate(360deg) scale(0.9); opacity: 0.5; }
}

:doodle {
  @grid: 15 / 100vw 100vh;
  gap: 4px;
}
@size: @r(30px, 80px);
background: hsla(@r(200, 280), 50%, 50%, @r(0.1, 0.4));
border-radius: 4px;
position: absolute;
left: @r(100%); top: @r(100%);
animation: pixel-float @r(5s, 15s) ease-in-out infinite;
@keyframes pixel-float {
  0%, 100% { transform: translate(0, 0) rotate(0); opacity: 0.2; }
  50% { transform: translate(@r(-40px, 40px), @r(-40px, 40px)) rotate(@r(90deg)); opacity: 0.6; }
}

:doodle {
  @grid: 12 / 100vmax;
}
:after {
  content: @p('△', '□', '◇', '○', '▽');
  color: hsla(@r(360), 70%, 70%, @r(0.3, 0.6));
  font-size: @r(2rem, 5rem);
  animation: drift @r(10s, 20s) linear infinite;
}
@keyframes drift {
  from { transform: rotate(0) translateY(0); }
  to { transform: rotate(360deg) translateY(-100px); }
}

:doodle {
  @grid: 1 / 100vw 100vh;
  background: radial-gradient(circle at center, #0f172a 0%, #020617 100%);
}
@content: @svg(
  viewBox: -50 -50 100 100;
  circle*450 {
    fill: hsla(@calc(200 + 40*@sin.n), 80%, 70%, @r(0.4, 0.9));
    r: @calc(@sqrt(@n/12));
    cx: @calc(@n*.618^4 * @cos(2*3.14*@n*.618));
    cy: @calc(@n*.618^4 * @sin(2*3.14*@n*.618));
  }
);

:doodle {
  @grid: 7x5 / 100vw 100vh;
  gap: 20px;
}
@size: @r(100px, 200px);
background: linear-gradient(@r(360deg), hsla(260, 60%, 50%, 0.8), hsla(220, 60%, 40%, 0.6));
border-radius: 12px;
box-shadow: 0 10px 30px rgba(0,0,0,0.4);
transform: perspective(1000px) rotateX(@r(-20deg, 20deg)) rotateY(@r(-20deg, 20deg));
animation: float3d @r(8s, 15s) ease-in-out infinite alternate;
@keyframes float3d {
  from { transform: perspective(1000px) rotateX(@r(-10deg)) rotateY(@r(-10deg)) translateZ(0); }
  to { transform: perspective(1000px) rotateX(@r(20deg)) rotateY(@r(20deg)) translateZ(50px); }
}

:doodle {
  @grid: 8x6 / 100vw 100vh;
}
@size: @r(50px, 100px);
position: absolute;
left: @r(100%); top: @r(100%);
@content: @p('🚀', '🪐', '👾', '🎨', '💡', '🤖', 'H', 'E', 'C', 'T', 'O', 'R');
font-size: @r(30px, 70px);
color: @p(#ffbe0b, #fb5607, #ff006e, #8338ec, #3a86ff);
text-shadow: 0 0 15px rgba(255,255,255,0.3);
animation: bounce @r(3s, 7s) ease-in-out infinite;
@keyframes bounce {
  0%, 100% { transform: translateY(0) scale(0.8); }
  50% { transform: translateY(-40px) scale(1.2); }
}
:hover { transform: scale(1.5) rotate(15deg); z-index: 100; }
